// Calcul surface polygone (Shoelace formula) — retourne m²
function calcSurface(pts) {
  let s = 0;
  const n = pts.length;
  for (let i=0; i<n; i++) {
    const j = (i+1)%n;
    s += pts[i].x * pts[j].y;
    s -= pts[j].x * pts[i].y;
  }
  return Math.abs(s/2);
}

